// Replace this array with your competitors, pricing pages, changelog URLs, or product pages.
const competitors = [
  { name: "Competitor A", url: "https://example.com/pricing", watch_for: "pricing, plans, positioning" },
  { name: "Competitor B", url: "https://example.org/features", watch_for: "features, integrations, headline changes" }
];

return competitors.map((competitor) => ({ json: competitor }));

const page = $json.body || $json.data || $json.html || JSON.stringify($json);
const text = String(page)
  .replace(/<script[\s\S]*?<\/script>/gi, " ")
  .replace(/<style[\s\S]*?<\/style>/gi, " ")
  .replace(/<[^>]+>/g, " ")
  .replace(/\s+/g, " ")
  .trim()
  .slice(0, 12000);

const staticData = $getWorkflowStaticData("global");
staticData.snapshots = staticData.snapshots || {};

const key = $json.url;
const previous = staticData.snapshots[key];
staticData.snapshots[key] = {
  captured_at: new Date().toISOString(),
  text
};

const changed = !previous || previous.text !== text;

return [{
  json: {
    name: $json.name,
    url: $json.url,
    watch_for: $json.watch_for,
    changed,
    previous_text: previous?.text || "",
    current_text: text,
    captured_at: staticData.snapshots[key].captured_at
  }
}];

const items = $input.all().map((item) => item.json);
const changed = items.filter((item) => item.changed);

const prompt = changed.length
  ? changed.map((item) => [
      `COMPETITOR: ${item.name}`,
      `URL: ${item.url}`,
      `WATCH FOR: ${item.watch_for}`,
      `PREVIOUS SNAPSHOT:\n${item.previous_text || "(first run - no previous snapshot)"}`,
      `CURRENT SNAPSHOT:\n${item.current_text}`
    ].join("\n")).join("\n\n---\n\n")
  : "No competitors changed since the last run. Create a short no-change digest.";

return [{
  json: {
    changed_count: changed.length,
    total_checked: items.length,
    prompt,
    recipient_email: "user@example.com"
  }
}];

const raw = $json.message?.content || $json.text || "";
const now = new Date().toISOString().slice(0, 10);
return [{
  json: {
    subject: `Competitor change digest - ${now}`,
    digest_html: raw.replace(/\n/g, "<br>"),
    recipient_email: $("Build Digest Prompt").first().json.recipient_email,
    changed_count: $("Build Digest Prompt").first().json.changed_count,
    total_checked: $("Build Digest Prompt").first().json.total_checked
  }
}];
